mapper.select:
select c.id, c.context, c.article_id, c.comment_user_id, c.root_id, c.parent_id, c.status, c.is_illegal, c.like_num, c.create_time, u.username, u.avatar, a.title as article_title, parent_comment.comment_user_id as reply_user_id, reply_user.username as reply_username, reply_user.avatar as reply_avatar from comment as c left join user as u on c.comment_user_id = u.id left join article as a on c.article_id = a.id left join comment as parent_comment on c.parent_id = parent_comment.id left join user as reply_user on parent_comment.comment_user_id = reply_user.id
and c.article_id = #{articleId}
and c.root_id = #{rootId}
and c.status = #{status}
and c.context like concat('%', #{context}, '%')
and u.username like concat('%', #{username}, '%')
and a.title like concat('%', #{title}, '%')
and c.is_illegal = #{isIllegal}
and c.create_time >= #{startTime}
and c.create_time <= #{endTime}
order by c.like_num desc, c.create_time desc
